    await assert.rejects(writer.create({ effortId: "../bad", createdAt: first.timestamp, checkpointId: first.payload.checkpointId, creationMode: "independent" }, first), /invalid/);
    await assert.rejects(writer.append({} as any), /invalid telemetry/);
    assert.equal(await writer.passive(association()), undefined); assert.equal(writer.isDegraded(), true);
    await mkdir(join(project, ".awf/metrics/tombstones"), { recursive: true, mode: 0o700 }); await writeFile(join(project, ".awf/metrics/tombstones/effort.json"), JSON.stringify({ nonce: "pruned", state: "committed" }), { mode: 0o600 });
    await assert.rejects(writer.create({ effortId: "effort", createdAt: first.timestamp, checkpointId: first.payload.checkpointId, creationMode: "independent" }, first), /pruned/);
