    const derived = creation("derived"); const writer = createLedgerWriter(defaultLedgerDependencies(join(project, ".pi/extensions/awf-dashboard/index.ts"))); await writer.create({ effortId: "derived", createdAt: derived.timestamp, checkpointId: derived.payload.checkpointId, creationMode: "derived", origin: { effortId: "origin", trajectoryId: "trajectory", anchorId: "anchor" } }, { ...derived, payload: { checkpointId: derived.payload.checkpointId, creationMode: "derived", originEffortId: "origin", originTrajectoryId: "trajectory", originAnchorId: "anchor" } }); await writer.shutdown();
    await writeFile(join(project, ".awf/metrics/efforts/derived/effort.json"), "not-json\n", { mode: 0o600 }); const corrupt = createLedgerWriter(defaultLedgerDependencies(join(project, ".pi/extensions/awf-dashboard/index.ts"))); await assert.rejects(corrupt.create({ effortId: "derived", createdAt: derived.timestamp, checkpointId: derived.payload.checkpointId, creationMode: "derived", origin: { effortId: "origin", trajectoryId: "trajectory", anchorId: "anchor" } }, { ...derived, payload: { checkpointId: derived.payload.checkpointId, creationMode: "derived", originEffortId: "origin", originTrajectoryId: "trajectory", originAnchorId: "anchor" } }), /already exists/); await corrupt.shutdown();
    const leases = join(project, ".awf/metrics/leases"); const disappearing = defaultLedgerDependencies(join(project, ".pi/extensions/awf-dashboard/index.ts")); await writeFile(join(leases, "disappearing.create.json"), JSON.stringify({ nonce: "old", owner: "old", expiresAt: new Date(0).toISOString() }), { mode: 0o600 }); const disappearingRead = disappearing.readFile; let disappeared = false; disappearing.readFile = async (path, encoding) => { if (!disappeared && path.endsWith("disappearing.create.json")) { disappeared = true; await rm(path); const error: any = new Error("gone"); error.code = "ENOENT"; throw error; } return disappearingRead(path, encoding); }; const disappearingEvent = creation("disappearing"); const disappearingWriter = createLedgerWriter(disappearing); await disappearingWriter.create({ effortId: "disappearing", createdAt: disappearingEvent.timestamp, checkpointId: disappearingEvent.payload.checkpointId, creationMode: "independent" }, disappearingEvent); await disappearingWriter.shutdown();
    await writeFile(join(leases, "invalid-expiry.create.json"), JSON.stringify({ nonce: "old", owner: "old", expiresAt: "bad" }), { mode: 0o600 }); const invalidExpiryEvent = creation("invalid-expiry"); const invalidExpiryWriter = createLedgerWriter(defaultLedgerDependencies(join(project, ".pi/extensions/awf-dashboard/index.ts"))); await assert.rejects(invalidExpiryWriter.create({ effortId: "invalid-expiry", createdAt: invalidExpiryEvent.timestamp, checkpointId: invalidExpiryEvent.payload.checkpointId, creationMode: "independent" }, invalidExpiryEvent), /ambiguous/); await invalidExpiryWriter.shutdown(); await rm(join(leases, "invalid-expiry.create.json"));
