    const oldReaddir = h.deps.ledger.readdir; h.deps.ledger.readdir = async () => { const error: any = new Error("readdir failed"); error.code = "EACCES"; throw error; }; await assert.rejects(execute(tool, base("select-route", { route: "direct" })), /readdir failed/); h.deps.ledger.readdir = oldReaddir;
