test("invariant: historical lifecycle projection excludes every illegal effect class", async () => {
  const make = (id: string, kind: string, payload: any, predecessors: string[] = ["create"], sessionId = "session", extra: any = {}) => ({ version: protocolVersion, eventId: id, idempotencyKey: `${id}-key`, effortId: "history", sessionId, timestamp: "2026-07-22T00:00:00Z", kind, predecessors, payload, ...extra });
  const create = make("create", "effort_created", { checkpointId: ".awf/memory/history.md", creationMode: "independent" }, []);
  const project = async (events: any[]) => { const projectRoot = await root(); const sessions = join(projectRoot, ".awf/metrics/efforts/history/sessions"); await mkdir(sessions, { recursive: true, mode: 0o700 }); const grouped = new Map<string, any[]>(); for (const event of events) grouped.set(event.sessionId, [...(grouped.get(event.sessionId) ?? []), event]); for (const [session, values] of grouped) await writeFile(join(sessions, `${session}.jsonl`), values.map((value) => JSON.stringify(value)).join("\n") + "\n", { mode: 0o600 }); const result = await projectLocalLifecycle(defaultLedgerDependencies(join(projectRoot, ".pi/extensions/awf-dashboard/index.ts")), "history"); await rm(projectRoot, { recursive: true, force: true }); return result; };
  const cases: Array<[string, any[], string]> = [
    ["mutation-before-create", [make("route", "route_selected", { route: "direct" })], "route"],
    ["duplicate-create", [create, make("create-two", "effort_created", { checkpointId: ".awf/memory/history.md", creationMode: "independent" })], "create-two"],
    ["association-without-trajectory", [create, make("associate", "session_associated", { associationOrigin: "manual", trajectoryId: "missing" }, ["create"], "child", { trajectoryId: "missing" })], "associate"],
    ["route-change-without-selection", [create, make("change", "route_changed", { route: "plan" })], "change"],
    ["second-route-selection", [create, make("route", "route_selected", { route: "direct" }), make("route-two", "route_selected", { route: "plan" }, ["route"])], "route-two"],
    ["phase-finish-without-start", [create, make("finish", "phase_finished", { phase: "planning", startEventId: "missing" })], "finish"],
    ["phase-overlap", [create, make("start", "phase_started", { phase: "planning" }), make("overlap", "phase_started", { phase: "implementation" }, ["start"])], "overlap"],
    ["resume-unknown", [create, make("resume", "trajectory_resumed", { trajectoryId: "missing", anchorId: "anchor" }, ["create"], "session", { trajectoryId: "missing" })], "resume"],
    ["close-unknown", [create, make("close", "trajectory_closed", { trajectoryId: "missing", anchorId: "anchor" }, ["create"], "session", { trajectoryId: "missing" })], "close"],
    ["fork-unknown-parent", [create, make("fork", "trajectory_forked", { trajectoryId: "child", parentTrajectoryId: "missing", forkAnchorId: "anchor" }, ["create"], "session", { trajectoryId: "child", parentTrajectoryId: "missing", forkAnchorId: "anchor" })], "fork"],
    ["duplicate-trajectory", [create, make("start", "trajectory_started", { trajectoryId: "one", anchorId: "a" }, ["create"], "session", { trajectoryId: "one" }), make("start-two", "trajectory_started", { trajectoryId: "one", anchorId: "b" }, ["start"], "session", { trajectoryId: "one" })], "start-two"],
    ["close-non-active", [create, make("one", "trajectory_started", { trajectoryId: "one", anchorId: "a" }, ["create"], "session", { trajectoryId: "one" }), make("two", "trajectory_started", { trajectoryId: "two", anchorId: "b" }, ["one"], "session", { trajectoryId: "two" }), make("close", "trajectory_closed", { trajectoryId: "one", anchorId: "a" }, ["two"], "session", { trajectoryId: "one" })], "close"],
    ["close-inactive", [create, make("start", "trajectory_started", { trajectoryId: "one", anchorId: "a" }, ["create"], "session", { trajectoryId: "one" }), make("close", "trajectory_closed", { trajectoryId: "one", anchorId: "a" }, ["start"], "session", { trajectoryId: "one" }), make("close-two", "trajectory_closed", { trajectoryId: "one", anchorId: "a" }, ["close"], "session", { trajectoryId: "one" })], "close-two"],
    ["complete-discovery", [create, make("complete", "effort_completed", { terminalEpoch: 1 })], "complete"],
    ["abandon-wrong-epoch", [create, make("abandon", "effort_abandoned", { terminalEpoch: 2 })], "abandon"],
    ["reopen-discovery", [create, make("reopen", "effort_reopened", { terminalEpoch: 2, trajectoryId: "new", anchorId: "a" }, ["create"], "session", { trajectoryId: "new" })], "reopen"],
    ["post-terminal", [create, make("abandon", "effort_abandoned", { terminalEpoch: 1 }), make("route", "route_selected", { route: "direct" }, ["abandon"])], "route"],
    ["broken-predecessor", [create, make("broken", "route_selected", { route: "direct" }, ["missing"], "other")], "broken"],
    ["concurrent-route", [create, make("left", "route_selected", { route: "direct" }, ["create"], "left"), make("right", "route_selected", { route: "plan" }, ["create"], "right")], "left"],
    ["repair-missing-source", [create, make("repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["missing"], replacement: { eventKind: "session_detached", payload: { reason: "manual" } } })], "repair"],
  ];
  for (const [name, events, rejected] of cases) { const projection = await project(events); assert.equal(projection.effectApplied.has(rejected), false, name); }
  const replacement = (eventKind: string, payload: any) => ({ eventKind, payload });
  const source = make("source", "route_selected", { route: "direct" });
  const repaired = await project([create, source, make("repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["source"], replacement: replacement("route_selected", { route: "plan" }) }, ["source"])]); assert.equal(repaired.route, "plan"); assert.equal(repaired.effectApplied.has("source"), false); assert.equal(repaired.effectApplied.has("repair"), true);
  const phase = make("phase", "phase_started", { phase: "planning" }, ["source"]); const multi = await project([create, source, phase, make("multi-repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["source", "phase"], replacement: replacement("route_selected", { route: "plan" }) }, ["phase"])]); assert.equal(multi.route, "plan"); assert.equal(multi.openPhases.size, 0); assert.equal(multi.effectApplied.has("multi-repair"), true);
  const fallback = await project([create, source, make("bad-repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["source"], replacement: replacement("trajectory_resumed", { trajectoryId: "missing", anchorId: "anchor" }) }, ["source"])]); assert.equal(fallback.route, "direct"); assert.equal(fallback.effectApplied.has("source"), true); assert.equal(fallback.effectApplied.has("bad-repair"), false);
  const concurrent = await project([create, source, make("left-repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["source"], replacement: replacement("route_selected", { route: "plan" }) }, ["source"], "left"), make("right-repair", "repair_applied", { proposalKind: "supersede-event", sourceEventIds: ["source"], replacement: replacement("route_selected", { route: "adr" }) }, ["source"], "right")]); assert.equal(concurrent.route, "direct"); assert.equal(concurrent.effectApplied.has("left-repair"), false); assert.equal(concurrent.effectApplied.has("right-repair"), false);
});

